mapper.insert:
INSERT INTO playlist_emotion (
  playlistemotionno,
  emotion
) VALUES (
  playlist_emotion_seq.NEXTVAL,
  #{emotion}
)

mapper.select:
SELECT playlistemotionno, emotion
FROM playlist_emotion
WHERE playlistemotionno = #{playlistemotionno}

mapper.update:
UPDATE playlist_emotion
SET emotion = #{emotion}
WHERE playlistemotionno = #{playlistemotionno}
